+/** Record a target-specific relation event for every live tracking factory. */
+export function setPairTrackingEvent(
+    world: World,
+    entity: Entity,
+    trait: Trait,
+    target: Entity,
+    eventType: EventType
+): void {
+    const eventsByFactory = world[$internal].pairTrackingEvents;
+    const key = getPairTrackingKey(trait, target);
+
+    for (const events of eventsByFactory.values()) {
+        let entityEvents = events.get(entity);
